# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, session, redirect, url_for, jsonify
import requests
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = 'your_secret_key'

oauth = OAuth(app)
openid_connect = oauth.register(
    name='oidc',
    client_id='your_client_id',
    client_secret='your_client_secret',
    access_token_url='https://your-provider/oauth/token',
    authorize_url='https://your-provider/authorize',
    api_base_url='https://your-provider/userinfo',
    client_kwargs={'scope': 'openid email profile'}
)

@app.route('/')
def index():
    if 'user' in session:
        return f'Hello, {session["user"]["name"]}!'
    else:
        redirect_to_provider = url_for('login', _external=True)
        return redirect(redirect_to_provider)

@app.route('/login')
def login():
    redirect_uri = url_for('authorize', _external=True)
    return openid_connect.authorize_redirect(redirect_uri)

@app.route('/authorize')
def authorize():
    token = openid_connect.authorize_access_token()
    resp = openid_connect.get('userinfo')
    user_info = resp.json()
    session['user'] = {
        'id': user_info['sub'],
        'name': user_info['name'],
        'email': user_info['email']
    }
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)